        build_stub(STUB_A_PROC_NR, ..., b'A', ..., HeapWindow::EMPTY);
        build_stub(STUB_B_PROC_NR, ..., b'B', ..., HeapWindow::EMPTY);
        build_stub(STUB_C_PROC_NR, ..., b'C', ..., HeapWindow::EMPTY);
