**vm_bootstrap (lines 232–277):**
```rust
unsafe fn vm_bootstrap() {
    let mut aspace = AddrSpace::new().expect("VM AddrSpace::new failed");
    let ttbr0_pa = aspace.ttbr0_pa;

    // Load VM server ELF from embedded binary
    let entry = crate::boot_image::elf::load_into(crate::boot_image::VM_ELF, &mut aspace)
        .expect("VM ELF load failed");

    // Allocate stack frame
    let stack_frame = alloc_frame().expect("VM stack frame alloc failed");
    aspace.map_page(VM_STACK_VA, stack_frame.addr(), Prot::RW_DATA)
        .expect("map_page(VM stack) failed");

    let asid = unsafe { alloc_asid() };

    // Populate VM's proc slot
    unsafe {
        let p = proc_slot_mut(VM_PROC_NR).expect("VM proc slot in range");
        p.regs.elr_el1 = entry;                        // Entry point
        p.regs.sp_el0 = VM_STACK_VA + PAGE_SIZE as u64;  // Stack top
        p.regs.spsr_el1 = STUB_SPSR_EL0;              // EL0 CPU flags
        p.ttbr0_pa = ttbr0_pa;                         // Page table root
        p.asid = asid;                                 // ASID for TLBI
        p.next_ready = None;
        p.rts_flags.store(0, Ordering::Relaxed);      // Runnable
    }

    // Forget the AddrSpace value (durable via ttbr0_pa)
    core::mem::forget(aspace);

    // Enqueue to run
    unsafe { sched::enqueue(VM_PROC_NR) };
}
```

**Stub D (user_stub.S lines 128–152):**
```asm
    .section .rodata.user_stub_d, "a", %progbits
    .balign 4
    .global _user_stub_d_start
_user_stub_d_start:
    movz    x20, #0x0100, lsl #16              // x20 = 0x0100_0000 (heap VA)
    mov     x19, #0                            // persistent counter
1:
    str     x19, [x20]                         // 1st iter: translation fault
                                               // kernel → RTS_PAGEFAULT
                                               // → send_pagefault_to_vm
                                               // → VM maps page via PT_MAP
                                               // → clears fault via CLEAR_PAGEFAULT
                                               // → store retries and succeeds
    add     x19, x19, #1
    b       1b
    .global _user_stub_d_end
_user_stub_d_end:
```

**Stub D Privilege (install_stub_d_priv, lines 484–504):**
```rust
unsafe fn install_stub_d_priv() {
    let pr: &mut Priv = unsafe { priv_slot_mut(STUB_D_PRIV_ID).expect("...") };
    pr.id = STUB_D_PRIV_ID;
    pr.proc_nr = Some(STUB_D_PROC_NR);
    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
    pr.trap_mask = TSK_T;  // Task-like: no IPC, no kernel calls
    pr.ipc_to.fill(0);     // Empty: no IPC allowed
    pr.k_call_mask.fill(0); // Empty: no kernel calls allowed
    pr.notify_pending.fill(0);
    pr.asyn_pending.fill(0);
    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
}
```

**Key: heap_window is UNUSED since 3.4b.** Stub D gets `HeapWindow::EMPTY`. The kernel routes *all* faults to VM; there is no inline kernel-resolved fast path anymore.

---

### 7. **Address Space API** (`/Users/kevinbarnard/src/minix-4/kernel/src/arch/aarch64/addrspace.rs` lines 70–140)

```rust
pub struct AddrSpace {
    pub ttbr0_pa: u64,  // L0 page-table root PA
}

impl AddrSpace {
    // Allocates L0 root; L1/L2/L3 allocated on demand
    pub fn new() -> Result<Self, MapError> {
        let l0 = alloc_frame().ok_or(MapError::OutOfMemory)?;
