#[unsafe(no_mangle)]
extern "C" fn do_page_fault(esr: u64, elr: u64, far: u64) {
    let ec = (esr >> 26) & 0x3F;     // Exception Class
    let iss = esr & 0xFF_FFFF;       // Instruction-Specific Syndrome

    // Validate: only EC=0x20 (instr abort) or EC=0x24 (data abort)
    if ec != 0x20 && ec != 0x24 {
        el0_sync_unexpected(esr, elr, far); // -> !
    }

    // Classify fault (arch-neutral for VM to read)
    let fsc = iss & 0x3F;  // Fault Status Code
    let mut flags = 0u32;
    if ec == 0x20 { flags |= PFF_INSTR; }
    if ec == 0x24 && (iss >> 6) & 1 != 0 { flags |= PFF_WRITE; }
    if matches!(fsc, 0x0D..=0x0F) { flags |= PFF_PERMISSION; }

    // CRITICAL: Permission faults (already-mapped with wrong AP) are rejected
    // Re-protecting (CoW, etc.) is future VM work
    if flags & PFF_PERMISSION != 0 {
        el0_sync_unexpected(esr, elr, far); // -> !
    }

    // Record fault + block on RTS_PAGEFAULT (capture scalars to avoid borrow issues)
    let (faulting_nr, name);
    {
        let p = unsafe { sched::current_proc_mut() }.expect("...");
        p.page_fault_state = PageFaultState { addr: far, flags, ip: elr };
        faulting_nr = p.nr;
        name = p.name[0];
        unsafe { sched::rts_set(p, RTS_PAGEFAULT) };  // Blocks proc
    }

    // KERNEL-ORIGINATED SEND to VM (slice 3.4b flow, not 3.2 fast-path)
    // The faulter stays blocked on RTS_PAGEFAULT across reschedule
    // until VM answers with SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)
    crate::ipc::send_pagefault_to_vm(faulting_nr, far, flags);

    let mut uart = Pl011::new();
    let _ = writeln!(uart, "[pf] proc={} far={far:#x} flags={flags:#x} -> VM",
        name as char,
    );
}
```

**Flow:** 
- Classify fault from ESR_EL1 (exception class + ISS fault status code)
- Record into proc's `page_fault_state` 
- Set `RTS_PAGEFAULT` (blocks proc on run-queue)
- **Call `send_pagefault_to_vm`** → kernel-originated IPC to VM server
- Handler returns; `trap.S` calls `el1_svc_tail` → `schedule_next` → VM runs

