**rts_set / rts_unset (sched.rs lines 180–208):**
```rust
pub unsafe fn rts_set(p: &mut Proc, flag: u32) {
    let was_runnable = p.rts_flags.load(Ordering::Relaxed) == 0;
    p.rts_flags.fetch_or(flag, Ordering::Relaxed);
    let nr = p.nr;
    if was_runnable {
        unsafe { dequeue(nr) }  // Remove from run queue if transitioning to blocked
    }
}

pub unsafe fn rts_unset(p: &mut Proc, flag: u32) {
    let prev = p.rts_flags.fetch_and(!flag, Ordering::Relaxed);
    let nr = p.nr;
    let now_runnable = (prev & !flag) == 0;  // Check if all flags cleared
    if now_runnable && prev != 0 {
        unsafe { enqueue(nr) }  // Re-enqueue if transitioning to runnable
    }
}
```

