pub unsafe fn schedule_next() {
    let next_nr = match pick_proc() {
        Some(nr) => nr,
        None => return,  // No runnable procs — stay on current
    };
    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);

    unsafe {
        let next = proc_slot_mut(next_nr).expect("...");
        set_tpidr_to(next);  // Park register frame in TPIDR_EL1

        // Install per-proc TTBR0 + ASID (every EL1 → EL0 transition)
        debug_assert!(next.ttbr0_pa != 0 && next.asid != 0, "...");
        crate::arch::aarch64::mmu::switch_ttbr0_with_asid(
            next.ttbr0_pa,
            next.asid,
        );

        // Flush any pending IPC message into new proc's user buffer
        crate::ipc::flush_deliver_msg(next);
    }
    // No return: el1_return_to_user continues from trap.S
}
