8	/// Base for kernel-call numbers. Matches MINIX 3 `KERNEL_CALL`.
9	pub const KERNEL_CALL: i32 = 0x600;
10	
11	#[allow(clippy::identity_op)] // explicit `+ 0` keeps the table aligned visually
12	pub const SYS_GETINFO: i32 = KERNEL_CALL + 0;
13	pub const SYS_PRIVCTL: i32 = KERNEL_CALL + 1;
14	pub const SYS_FORK: i32 = KERNEL_CALL + 2;
15	pub const SYS_EXEC: i32 = KERNEL_CALL + 3;
16	pub const SYS_EXIT: i32 = KERNEL_CALL + 4;
17	pub const SYS_COPY: i32 = KERNEL_CALL + 5;
18	pub const SYS_SAFECOPY: i32 = KERNEL_CALL + 6;
19	pub const SYS_IRQCTL: i32 = KERNEL_CALL + 7;
20	pub const SYS_VMCTL: i32 = KERNEL_CALL + 8;
21	pub const SYS_SCHEDULE: i32 = KERNEL_CALL + 9;
22	pub const SYS_SETALARM: i32 = KERNEL_CALL + 10;
23	pub const SYS_TIMES: i32 = KERNEL_CALL + 11;
24	pub const SYS_DIAGCTL: i32 = KERNEL_CALL + 12;
25	pub const SYS_SETGRANT: i32 = KERNEL_CALL + 13;
26	
27	/// Number of kernel calls defined through Phase 3. Slice 3.3 adds no new
28	/// `SYS_*` (it fills in `SYS_VMCTL`'s subcalls instead), so the count is
29	/// unchanged from Phase 2 — the rename just gives `system/mod.rs`'s
30	/// arm-coverage const-assert a phase-appropriate name as Phase 3 lands.
31	pub const NR_KERN_CALLS_PHASE3: usize = 14;
32	
33	/// Size of the privilege-table kernel-call mask, in bits. Sized as a single
34	/// `u32` chunk (32 slots) to leave headroom past Phase 2's 14 calls while
35	/// keeping the bitmap a single word per privilege slot.
36	pub const NR_SYS_CALLS: usize = 32;
37	
38	const _: () = assert!(NR_SYS_CALLS >= NR_KERN_CALLS_PHASE3);
39	const _: () = assert!(NR_SYS_CALLS % 32 == 0);
40	
41	// ---------------------------------------------------------------------------
42	// `SYS_GETINFO` request sub-types.
43	//
44	// `SYS_GETINFO` is a multi-purpose introspection call: the request sub-type
45	// in the first 4 bytes of the message payload selects what the kernel reports
