1	//! Slice-3.1b userland bootstrap: per-process address spaces with 8-bit
2	//! ARMv8 ASIDs.
3	//!
4	//! Each of the three EL0 stubs (A, B, C — the slice 2.5 / 2.6 regression
5	//! coverage) gets its own [`AddrSpace`] built from the slice-3.1a frame
6	//! allocator. Code and stack pages are allocated as fresh frames, the
7	//! stub blob is copied in via HHDM (`mm::phys_to_hhdm`), and the
8	//! resulting `(ttbr0_pa, asid)` is stored on the proc slot. The scheduler
9	//! ([`crate::proc::sched::schedule_next`]) installs that TTBR0 on every
10	//! EL1 → EL0 transition.
11	//!
12	//! What slice 3.1a's smoke test exercised in isolation — `AddrSpace::new`,
13	//! `map_page`, `walk_pt`, the free-list reuse on `destroy` — now drives
14	//! the three real EL0 stubs.
15	//!
16	//! What this slice does *not* do:
17	//!   - Recover from page faults. EC=0x20 / EC=0x24 still panic via
18	//!     [`super::exception::el0_sync_unexpected`]; slice 3.1b extends that
19	//!     handler's ISS decoder so the dump is informative, but the policy
20	//!     is still "halt" — real `do_page_fault` + `RTS_PAGEFAULT` land in
21	//!     slice 3.2.
22	//!   - Cross-AS IPC delivery. The SVC handler runs in the caller's TTBR0,
23	//!     so single-AS reads in `ipc::message` still walk correctly; slice
24	//!     3.4's HHDM-walk redesign of `flush_deliver_msg` swaps that out
25	//!     once VM exists.
26	//!   - Install a kernel-shared global mapping for the EL0 stubs. The
27	//!     code page is mapped RO + EL0-executable into each per-proc AS
28	//!     individually (zero shared frames).
29	
30	use core::sync::atomic::Ordering;
31	
32	use minix4_kernel_shared::callnr::{KERNEL_CALL, SYS_GETINFO};
33	use minix4_kernel_shared::com::{RS_PROC_NR, SYSTEM, VM_PROC_NR, boot_endpoint};
34	use minix4_kernel_shared::{PrivId, ProcNr};
35	
36	use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
37	use crate::arch::aarch64::asid::alloc_asid;
38	use crate::arch::aarch64::mmu::{self, PAGE_SIZE, flush_icache_range};
39	use crate::mm::{Frame, alloc_frame, phys_to_hhdm};
40	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
41	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC, TSK_T, USR_T};
42	use crate::proc::sched;
43	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
44	use crate::proc::{HeapWindow, Priv, Proc};
45	
46	// ----- EL0 virtual addresses ------------------------------------------------
47	
48	/// VA at which stub A's code page is mapped.
49	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
50	/// VA at which stub A's stack page is mapped.
51	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
52	
53	/// VA at which stub B's code page is mapped.
54	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
55	/// VA at which stub B's stack page is mapped.
56	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
57	
58	/// VA at which stub C's code page is mapped.
59	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
60	/// VA at which stub C's stack page is mapped.
61	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
62	
63	/// VA at which stub D's code page is mapped.
64	pub const USER_CODE_VA_D: u64 = 0x0043_0000;
65	/// VA at which stub D's stack page is mapped.
66	pub const USER_STACK_VA_D: u64 = 0x0083_0000;
67	
68	// Stub D's heap VA (`0x0100_0000`) lives only in `user_stub.S`'s stub D blob
69	// now: D maps/unmaps it itself via `SYS_VMCTL`, so the kernel needs no
70	// heap-window constant for it (slice 3.2's kernel-as-VM window is bypassed).
71	
72	/// First proc-table slot beyond the boot image — `ProcNr(11)`.
73	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
74	/// Second stub slot, just after A.
75	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
76	/// Slice-2.6 kernel-call client. Slot 13 — one past the slice-2.5 pair.
77	const STUB_C_PROC_NR: ProcNr = ProcNr::new(13);
78	/// Slice-3.2 page-fault demo. Slot 14.
79	const STUB_D_PROC_NR: ProcNr = ProcNr::new(14);
80	
81	/// Privilege-table slots for the four stubs. Boot image uses 0..=15;
82	/// 16, 17, 18, and 19 are the first free entries.
83	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
84	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
85	const STUB_C_PRIV_ID: PrivId = PrivId::new(18);
86	const STUB_D_PRIV_ID: PrivId = PrivId::new(19);
87	
88	// SPSR_EL1 to install on each stub's `eret`. Matches slice 2.4: IRQs
89	// unmasked at EL0 (bit 7 = 0), debug + SError + FIQ masked. EL0t.
90	const STUB_SPSR_EL0: u64 = 0x340;
91	
92	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
93	
94	unsafe extern "C" {
95	    static _user_stub_a_start: u8;
96	    static _user_stub_a_end: u8;
97	    static _user_stub_b_start: u8;
98	    static _user_stub_b_end: u8;
99	    static _user_stub_c_start: u8;
100	    static _user_stub_c_end: u8;
101	    static _user_stub_d_start: u8;
102	    static _user_stub_d_end: u8;
103	}
104	
105	/// VA at which the VM server's stack page is mapped. Distinct from VM's ELF
106	/// segments (loaded from `0x0010_0000` up by `servers/vm/user.ld`) and from
107	/// every EL0 stub VA.
108	const VM_STACK_VA: u64 = 0x0020_0000; // 2 MiB
109	
110	// ----- Bootstrap ----------------------------------------------------------
111	
112	/// Build three per-process address spaces (one per EL0 stub), populate
113	/// their proc + priv slots, and enqueue them on the scheduler.
114	///
115	/// Compared to slice 2.5/2.6 this:
116	///   - Drops the static `L0_TABLE`/.../`L3_STACK_TABLE` + `USER_*_PAGE_*`
117	///     arrays. Every frame is allocated from `mm::alloc_frame`.
118	///   - Hands each stub its own `(ttbr0_pa, asid)` via
119	///     [`build_stub`] + [`AddrSpace`].
120	///   - No longer installs a single TTBR0 from boot context; the scheduler
121	///     installs per-proc TTBR0 + ASID on every EL1 → EL0 transition.
122	///
123	/// SAFETY: must be called exactly once from `kmain` after `proc::init`,
124	/// `mm::set_hhdm_offset`, and `mm::init_from_limine_memmap`. Single-
125	/// threaded boot context; no other reference into the named proc slots
126	/// or the frame allocator may be live concurrently.
127	pub unsafe fn userland_bootstrap() {
128	    // 1. Verify Limine left MAIR_EL1 + TCR_EL1 in the shape our walker
129	    //    + per-proc TTBR0 install expect. The slice-3.1b TCR_EL1.AS = 0
130	    //    assert was added inside `assert_tcr_el1_ttbr0_ready`.
131	    mmu::assert_mair_normal_wb();
132	    mmu::assert_tcr_el1_ttbr0_ready();
133	
134	    // 2. Clear TCR_EL1.EPD0 once. Per-proc TTBR0 install happens at every
135	    //    context switch via `proc::sched::schedule_next`.
136	    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
137	    unsafe { mmu::enable_ttbr0_walks_once() };
138	
139	    // 2.5. Load the real VM server (slice 3.4) before the stubs so it takes
140	    //      ASID 1 and is enqueued first. Its `RECEIVE(ANY)` blocks immediately
141	    //      (no senders yet), leaving the run queue free for the band-8 stubs.
142	    // SAFETY: single-threaded boot; sole writer of VM's proc slot + allocator.
143	    unsafe { vm_bootstrap() };
144	
145	    // 3. Build each stub. Sequential calls — each build_stub allocates
146	    //    fresh frames + a fresh AddrSpace and writes its proc slot.
147	    // SAFETY: single-threaded boot; build_stub only touches its own
148	    // allocated state + the named proc slot.
149	    unsafe {
150	        build_stub(
151	            STUB_A_PROC_NR,
152	            STUB_A_PRIV_ID,
153	            b'A',
154	            &_user_stub_a_start,
155	            &_user_stub_a_end,
156	            USER_CODE_VA_A,
157	            USER_STACK_VA_A,
158	            HeapWindow::EMPTY,
159	        );
160	        build_stub(
161	            STUB_B_PROC_NR,
162	            STUB_B_PRIV_ID,
163	            b'B',
164	            &_user_stub_b_start,
165	            &_user_stub_b_end,
166	            USER_CODE_VA_B,
167	            USER_STACK_VA_B,
168	            HeapWindow::EMPTY,
169	        );
170	        build_stub(
171	            STUB_C_PROC_NR,
172	            STUB_C_PRIV_ID,
173	            b'C',
174	            &_user_stub_c_start,
175	            &_user_stub_c_end,
176	            USER_CODE_VA_C,
177	            USER_STACK_VA_C,
178	            HeapWindow::EMPTY,
179	        );
180	        build_stub(
181	            STUB_D_PROC_NR,
182	            STUB_D_PRIV_ID,
183	            b'D',
184	            &_user_stub_d_start,
185	            &_user_stub_d_end,
186	            USER_CODE_VA_D,
187	            USER_STACK_VA_D,
188	            // D faults on first touch of its heap page; the kernel routes the
189	            // fault to the VM server (slice 3.4b). `heap_window` is unused now
190	            // — the slice-3.2 kernel-as-VM fast path is gone — so EMPTY.
191	            HeapWindow::EMPTY,
192	        );
193	    }
194	
195	    // 4. Install priv slots — unchanged from slice 2.6.
196	    // SAFETY: single-threaded boot; sequential mutable borrows on
197	    // priv-table slots 16, 17, 18.
198	    unsafe { install_stub_privs() };
199	
200	    // 5. Enqueue all three on the scheduler.
201	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrows
202	    // live at this point.
203	    unsafe {
204	        sched::enqueue(STUB_A_PROC_NR);
205	        sched::enqueue(STUB_B_PROC_NR);
206	        sched::enqueue(STUB_C_PROC_NR);
207	        sched::enqueue(STUB_D_PROC_NR);
208	    }
209	
210	    // 6. One-shot diagnostic: dump per-proc (ttbr0_pa, asid) so the
211	    //    boot log proves each stub has its own distinct AS.
212	    //    SAFETY: single-threaded boot; read-only.
213	    unsafe { print_addrspace_summary() };
214	}
215	
216	/// Load the embedded VM server ELF into a fresh address space, prime its
217	/// entry/stack registers, and make it runnable.
218	///
219	/// Unlike the hand-coded stubs (which use ad-hoc proc/priv slots), VM occupies
220	/// its *real* boot slot `VM_PROC_NR`: `proc::init` → `init_boot_image` already
221	/// populated VM's name, priority, endpoint, and privilege slot (`trap_mask =
222	/// SRV_T` → RECEIVE ANY + SEND to any active slot; `k_call_mask` covering
223	/// `SYS_VMCTL`). So this fills in only the address space + EL0 entry state and
224	/// clears the boot `RTS_NO_PRIV` block. No `install_*_priv` helper is needed.
225	///
226	/// The `AddrSpace` is `mem::forget`-ed for the same reason as [`build_stub`]:
227	/// the page-table tree is now owned via `Proc::ttbr0_pa`.
228	///
229	/// SAFETY: single-threaded boot; the only writer of VM's proc slot and the
230	/// frame allocator here. Must run after `mm::init_from_limine_memmap` and
231	/// before `sched::run`.
232	unsafe fn vm_bootstrap() {
233	    use crate::arch::aarch64::uart::Pl011;
234	    use core::fmt::Write;
235	
236	    let mut aspace = AddrSpace::new().expect("VM AddrSpace::new failed");
237	    let ttbr0_pa = aspace.ttbr0_pa;
238	
239	    let entry = crate::boot_image::elf::load_into(crate::boot_image::VM_ELF, &mut aspace)
240	        .expect("VM ELF load failed");
241	
242	    // Stack: one zeroed RW page; SP starts at its top.
243	    let stack_frame = alloc_frame().expect("VM stack frame alloc failed");
244	    aspace
245	        .map_page(VM_STACK_VA, stack_frame.addr(), Prot::RW_DATA)
246	        .expect("map_page(VM stack) failed");
247	
248	    let asid = unsafe { alloc_asid() };
249	
250	    // SAFETY: single-threaded boot; sole borrow of VM's slot.
251	    unsafe {
252	        let p = proc_slot_mut(VM_PROC_NR).expect("VM proc slot in range");
253	        p.regs.elr_el1 = entry;
254	        p.regs.sp_el0 = VM_STACK_VA + PAGE_SIZE as u64;
255	        p.regs.spsr_el1 = STUB_SPSR_EL0;
256	        p.ttbr0_pa = ttbr0_pa;
257	        p.asid = asid;
258	        p.next_ready = None;
259	        // Clear the boot RTS_NO_PRIV: VM now has an address space and can run.
260	        p.rts_flags.store(0, Ordering::Relaxed);
261	
262	        let _ = writeln!(
263	            Pl011::new(),
264	            "[as] vm nr={} ttbr0_pa={:#x} asid={} entry={:#x}",
265	            p.nr.get(),
266	            p.ttbr0_pa,
267	            p.asid,
268	            entry,
269	        );
270	    }
271	
272	    // The page-table tree is durable via `ttbr0_pa`; don't run `destroy`.
273	    core::mem::forget(aspace);
274	
275	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrow is live.
276	    unsafe { sched::enqueue(VM_PROC_NR) };
277	}
278	
279	/// Build one stub's address space: allocate L0 + code + stack frames,
280	/// copy the stub blob into the code frame, install RX/RW mappings, and
281	/// write `(ttbr0_pa, asid)` into the proc slot.
282	///
283	/// `aspace` is intentionally `mem::forget`-ed at the end: the page-table
284	/// tree is now owned by the proc (via its `ttbr0_pa`); the kernel will
285	/// only reach into it again via HHDM walks. `AddrSpace::destroy` would
286	/// recursively free every L1/L2/L3 frame plus the L0 root, which is
287	/// exactly what we don't want.
288	///
289	/// SAFETY: single-threaded boot; this is the only writer of `nr`'s proc
290	/// slot. `stub_start..stub_end` must be a valid contiguous rodata range
291	/// in the kernel image; the linker guarantees both.
292	unsafe fn build_stub(
293	    nr: ProcNr,
294	    priv_id: PrivId,
295	    id: u8,
296	    stub_start: *const u8,
297	    stub_end: *const u8,
298	    code_va: u64,
299	    stack_va: u64,
300	    heap_window: HeapWindow,
301	) {
302	    // Per-proc page-table tree. AddrSpace::new allocates and zeroes the
303	    // L0 root via the frame allocator.
304	    let mut aspace =
305	        AddrSpace::new().expect("AddrSpace::new failed during userland_bootstrap");
306	    let ttbr0_pa = aspace.ttbr0_pa;
307	
308	    // Code frame: allocate, copy stub bytes in via HHDM, flush I-cache,
309	    // map RO + EL0-executable.
310	    let code_frame = alloc_frame()
311	        .expect("code frame alloc failed during userland_bootstrap");
312	    // SAFETY: stub_start/stub_end are rodata symbols inside the kernel
313	    // image; the new code frame is exclusively ours (just allocated, not
314	    // yet mapped into any AS) and HHDM-mapped.
315	    unsafe { copy_stub_into_frame(code_frame, stub_start, stub_end) };
316	    aspace
317	        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
318	        .expect("map_page(code) during userland_bootstrap");
319	
320	    // Stack frame: zeroed by `alloc_frame`, mapped RW + EL0-no-execute.
321	    let stack_frame = alloc_frame()
322	        .expect("stack frame alloc failed during userland_bootstrap");
323	    aspace
324	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
325	        .expect("map_page(stack) during userland_bootstrap");
326	
327	    // Hand the AddrSpace's root over to the proc slot.
328	    // SAFETY: single-threaded boot; this is the only `&mut Proc` borrow
329	    // at this nr right now.
330	    let asid = unsafe { alloc_asid() };
331	    unsafe {
332	        let p = proc_slot_mut(nr).expect("stub proc slot in range");
333	        populate_stub_slot(
334	            p,
335	            nr,
336	            priv_id,
337	            id,
338	            code_va,
339	            stack_va + PAGE_SIZE as u64,
340	            ttbr0_pa,
341	            asid,
342	            heap_window,
343	        );
344	    }
345	
346	    // The page-table tree is durable via `ttbr0_pa`. Drop the AddrSpace
347	    // value without running its (no-op-today, but defensively forget'd)
348	    // destructor — leaving `AddrSpace::destroy` reserved for exit/exec
349	    // paths that actually want to tear an AS down.
350	    core::mem::forget(aspace);
351	}
352	
353	/// Copy `[stub_start, stub_end)` into `frame` (resolved via HHDM) and
354	/// flush the I-cache so the upcoming EL0 fetch sees the new bytes.
355	///
356	/// SAFETY: `frame` must be exclusively owned (not yet mapped anywhere)
357	/// and the HHDM mapping for its PA must be live. `stub_start..stub_end`
358	/// must be a valid byte range in the kernel image.
359	unsafe fn copy_stub_into_frame(
360	    frame: Frame,
361	    stub_start: *const u8,
362	    stub_end: *const u8,
363	) {
364	    // SAFETY: end >= start by linker layout; offset_from is well-defined
365	    // on a single rodata symbol pair.
366	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
367	    assert!(len > 0 && len <= PAGE_SIZE);
368	    // SAFETY: caller's invariants hold; we have the sole pointer to this
369	    // frame, and HHDM is the only mapping.
370	    unsafe {
371	        let dst = phys_to_hhdm(frame.addr()) as *mut u8;
372	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
373	        flush_icache_range(dst as u64, len);
374	    }
375	}
376	
377	/// Write all per-stub fields into `p`. Extends slice 2.5's helper with
378	/// `ttbr0_pa` and `asid` — the rest mirrors slice 2.6.
379	fn populate_stub_slot(
380	    p: &mut Proc,
381	    nr: ProcNr,
382	    priv_id: PrivId,
383	    id: u8,
384	    entry_va: u64,
385	    stack_top: u64,
386	    ttbr0_pa: u64,
387	    asid: u8,
388	    heap_window: HeapWindow,
389	) {
390	    // Name: `id` followed by "-stub\0..." padding. Lets the clock tick
391	    // handler print `name[0]` to identify which stub is running.
392	    p.name = [0; 16];
393	    p.name[0] = id;
394	    p.name[1] = b'-';
395	    p.name[2] = b's';
396	    p.name[3] = b't';
397	    p.name[4] = b'u';
398	    p.name[5] = b'b';
399	
400	    p.nr = nr;
401	    p.endpoint = boot_endpoint(nr);
402	    p.priv_id = Some(priv_id);
403	    p.priority = crate::proc::table::SRV_Q;
404	    // 5 ticks per quantum = 50 ms at 100 Hz.
405	    p.quantum_ms = 5;
406	    p.quantum_left = p.quantum_ms as u64;
407	
408	    // EL0 entry state.
409	    p.regs.elr_el1 = entry_va;
410	    p.regs.sp_el0 = stack_top;
411	    p.regs.spsr_el1 = STUB_SPSR_EL0;
412	
413	    // Per-proc address space. Stored on the slot; the scheduler reads
414	    // both on every EL1 → EL0 transition.
415	    p.ttbr0_pa = ttbr0_pa;
416	    p.asid = asid;
417	
418	    // Kernel-resolved heap window (slice 3.2). Empty for A/B/C.
419	    p.page_fault_state = crate::proc::PageFaultState::EMPTY;
420	    p.heap_window = heap_window;
421	
422	    // Run-queue link starts cleared — `sched::enqueue` sets it.
423	    p.next_ready = None;
424	
425	    // Mark runnable.
426	    p.rts_flags.store(0, Ordering::Relaxed);
427	}
428	
429	/// Install priv slots for A, B, C. Unchanged from slice 2.6.
430	///
431	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, 18
432	/// sequentially.
433	unsafe fn install_stub_privs() {
434	    // SAFETY: sequential mutable borrow.
435	    unsafe {
436	        install_one_stub_priv(STUB_A_PRIV_ID, STUB_A_PROC_NR, STUB_B_PRIV_ID);
437	    }
438	    // SAFETY: A's borrow has been dropped.
439	    unsafe {
440	        install_one_stub_priv(STUB_B_PRIV_ID, STUB_B_PROC_NR, STUB_A_PRIV_ID);
441	    }
442	    // SAFETY: B's borrow has been dropped.
443	    unsafe {
444	        install_stub_c_priv();
445	    }
446	    // SAFETY: C's borrow has been dropped.
447	    unsafe {
448	        install_stub_d_priv();
449	    }
450	}
451	
452	/// Install stub C's priv slot. Differs from the A/B helper: trap_mask =
453	/// USR_T (SENDREC only), ipc_to opened just to SYSTEM, k_call_mask
454	/// opened just to `SYS_GETINFO`.
455	///
456	/// SAFETY: single-threaded boot; mutates only priv-table slot
457	/// `STUB_C_PRIV_ID`.
458	unsafe fn install_stub_c_priv() {
459	    let system_priv_id = {
460	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
461	        let table = unsafe { proc_table_ref() };
462	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
463	        table[idx]
464	            .priv_id
465	            .expect("SYSTEM priv populated by proc::init")
466	    };
467	
468	    // SAFETY: priv index in-range; no overlapping reference held.
469	    let pr: &mut Priv =
470	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
471	    pr.id = STUB_C_PRIV_ID;
472	    pr.proc_nr = Some(STUB_C_PROC_NR);
473	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
474	    pr.trap_mask = USR_T;
475	    pr.ipc_to.fill(0);
476	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
477	    pr.k_call_mask.fill(0);
478	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
479	    pr.notify_pending.fill(0);
480	    pr.asyn_pending.fill(0);
481	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
482	}
483	
484	/// Install stub D's priv slot (slice 3.4b). D reverts to a pure fault-on-touch
485	/// demo: it touches an unmapped heap page and the kernel routes the fault to
486	/// the VM server. D issues no IPC and no kernel calls, so it gets
487	/// `trap_mask = TSK_T` with empty `ipc_to` / `k_call_mask`.
488	///
489	/// SAFETY: single-threaded boot; mutates only priv-table slot
490	/// `STUB_D_PRIV_ID`.
491	unsafe fn install_stub_d_priv() {
492	    // SAFETY: priv index in-range; no overlapping reference held.
493	    let pr: &mut Priv =
494	        unsafe { priv_slot_mut(STUB_D_PRIV_ID).expect("stub D priv slot in range") };
495	    pr.id = STUB_D_PRIV_ID;
496	    pr.proc_nr = Some(STUB_D_PROC_NR);
497	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
498	    pr.trap_mask = TSK_T;
499	    pr.ipc_to.fill(0);
500	    pr.k_call_mask.fill(0);
501	    pr.notify_pending.fill(0);
502	    pr.asyn_pending.fill(0);
503	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
504	}
505	
506	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
507	/// stub is permitted to send/notify (encoded as a single bit in
508	/// `ipc_to`).
509	///
510	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
511	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
512	    // SAFETY: priv index in-range; no overlapping reference held.
513	    let pr: &mut Priv =
514	        unsafe { priv_slot_mut(id).expect("stub priv slot in range") };
515	    pr.id = id;
516	    pr.proc_nr = Some(owner);
517	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
518	    pr.trap_mask = SRV_T;
519	    pr.ipc_to.fill(0);
520	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
521	    pr.k_call_mask.fill(0);
522	    pr.notify_pending.fill(0);
523	    pr.asyn_pending.fill(0);
524	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
525	}
526	
527	/// Print one line per stub showing its `(ttbr0_pa, asid)`. Run once at
528	/// the end of `userland_bootstrap`; proves each stub has a distinct
529	/// per-proc address space.
530	///
531	/// SAFETY: single-threaded boot; read-only borrows on proc slots 11/12/13/14.
532	unsafe fn print_addrspace_summary() {
533	    use crate::arch::aarch64::uart::Pl011;
534	    use core::fmt::Write;
535	    let mut uart = Pl011::new();
536	    let _ = writeln!(uart);
537	    for &nr in &[STUB_A_PROC_NR, STUB_B_PROC_NR, STUB_C_PROC_NR, STUB_D_PROC_NR] {
538	        // SAFETY: sequential read-only borrow of the slot; no other
539	        // reference held while we read.
540	        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
541	        let _ = writeln!(
542	            uart,
543	            "[as] stub {} nr={} ttbr0_pa={:#x} asid={}",
544	            p.name[0] as char,
545	            p.nr.get(),
546	            p.ttbr0_pa,
547	            p.asid,
548	        );
549	    }
550	}
551

